Color Function(String? pitchType) usePitchTypeColor() {
  final context = useContext();
  return (String? pitchType) {
    return context.isDarkMode
        ? switch (pitchType) {
            '4_seam_fastball' => ColorManager.darkPitchTypeFourSeamFastBall,
            'sinker' => ColorManager.darkPitchTypeSinker,
            'cutter' => ColorManager.darkPitchTypeCutter,
            'changeup' => ColorManager.darkPitchTypeChangeup,
            'splitter' => ColorManager.darkPitchTypeSplitter,
            'forkball' => ColorManager.darkPitchTypeForkball,
            'screwball' => ColorManager.darkPitchTypeScrewball,
            'curveball' => ColorManager.darkPitchTypeCurveball,
            'knuckle_curve' => ColorManager.darkPitchTypeKnuckleCurve,
            'slurve' => ColorManager.darkPitchTypeSlurve,
            'slider' => ColorManager.darkPitchTypeSlider,
            'sweeper' => ColorManager.darkPitchTypeSweaper,
            'knuckleball' => ColorManager.darkPitchTypeKnuckleball,
            'eephus' => ColorManager.darkPitchTypeEephus,
            'excluded' => ColorManager.darkPitchTypeEephus,
            _ => ColorManager.darkPitchTypeEephus,
          }
        : switch (pitchType) {
            '4_seam_fastball' => ColorManager.pitchTypeFourSeamFastBall,
            'sinker' => ColorManager.pitchTypeSinker,
            'cutter' => ColorManager.pitchTypeCutter,
            'changeup' => ColorManager.pitchTypeChangeup,
            'splitter' => ColorManager.pitchTypeSplitter,
            'forkball' => ColorManager.pitchTypeForkball,
            'screwball' => ColorManager.pitchTypeScrewball,
            'curveball' => ColorManager.pitchTypeCurveball,
            'knuckle_curve' => ColorManager.pitchTypeKnuckleCurve,
            'slurve' => ColorManager.pitchTypeSlurve,
            'slider' => ColorManager.pitchTypeSlider,
            'sweeper' => ColorManager.pitchTypeSweaper,
            'knuckleball' => ColorManager.pitchTypeKnuckleball,
            'eephus' => ColorManager.pitchTypeEephus,
            'excluded' => ColorManager.pitchTypeEephus,
            _ => ColorManager.pitchTypeEephus,
          };
  };
}

String Function(String? pitchType) useTranslatePitchType() {
  final context = useContext();
  return useCallback(
    (String? originalPitchType) {
      return switch (originalPitchType) {
        null || 'none' => '-',
        '4_seam_fastball' => context.l10n.pitch_type__4_seam_fastball,
        'changeup' => context.l10n.pitch_type__changeup,
        'curveball' => context.l10n.pitch_type__curveball,
        'cutter' => context.l10n.pitch_type__cutter,
        'eephus' => context.l10n.pitch_type__eephus,
        'excluded' => context.l10n.pitch_type__excluded,
        'forkball' => context.l10n.pitch_type__forkball,
        'knuckleball' => context.l10n.pitch_type__knuckleball,
        'knuckle_curve' => context.l10n.pitch_type__knuckle_curve,
        'screwball' => context.l10n.pitch_type__screwball,
        'sinker' => context.l10n.pitch_type__sinker,
        'slider' => context.l10n.pitch_type__slider,
        'slurve' => context.l10n.pitch_type__slurve,
        'splitter' => context.l10n.pitch_type__splitter,
        'sweeper' => context.l10n.pitch_type__sweeper,
        _ => originalPitchType,
      };
    },
  );
}

